import{_ as o,o as t,c as a,ag as i}from"./chunks/framework.YaIgwL5o.js";const c=JSON.parse('{"title":"Video & Audio","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/media.md","filePath":"tutorials/media.md"}'),l={name:"tutorials/media.md"};function r(d,e,n,s,u,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="video-audio" tabindex="-1">Video &amp; Audio <a class="header-anchor" href="#video-audio" aria-label="Permalink to &quot;Video &amp; Audio&quot;">​</a></h1><h2 id="video" tabindex="-1">Video <a class="header-anchor" href="#video" aria-label="Permalink to &quot;Video&quot;">​</a></h2><h3 id="from-a-url" tabindex="-1">From a URL <a class="header-anchor" href="#from-a-url" aria-label="Permalink to &quot;From a URL&quot;">​</a></h3><ol><li>Click the <strong>Video</strong> button in the toolbar.</li><li>Paste a video URL (MP4, WebM, or Ogg).</li><li>The video element appears on the slide with playback controls.</li></ol><h3 id="by-uploading" tabindex="-1">By uploading <a class="header-anchor" href="#by-uploading" aria-label="Permalink to &quot;By uploading&quot;">​</a></h3><ol><li>Click the upload arrow next to the Video button.</li><li>Select a video file from your computer.</li><li>The file is uploaded to the server and embedded on the slide.</li></ol><h3 id="video-properties" tabindex="-1">Video properties <a class="header-anchor" href="#video-properties" aria-label="Permalink to &quot;Video properties&quot;">​</a></h3><p>Select the video element to configure in the right panel:</p><ul><li><strong>Controls</strong> — show/hide playback controls</li><li><strong>Autoplay</strong> — start playback when the slide becomes active</li><li><strong>Loop</strong> — repeat when finished</li><li><strong>Muted</strong> — start with audio muted (required for autoplay in most browsers)</li><li><strong>Object Fit</strong> — <code>contain</code> or <code>cover</code></li><li><strong>Poster</strong> — a thumbnail image shown before playback starts</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For autoplay to work in most browsers, you need to also enable <strong>Muted</strong>. Browsers block unmuted autoplay to prevent unwanted audio.</p></div><h2 id="audio" tabindex="-1">Audio <a class="header-anchor" href="#audio" aria-label="Permalink to &quot;Audio&quot;">​</a></h2><ol><li>Click the <strong>Audio</strong> button in the toolbar (under the media section).</li><li>Enter an audio file URL or upload a file.</li><li>An audio player element appears on the slide.</li></ol><p>Audio elements support the same controls, autoplay, loop, and muted options as video.</p>',13)])])}const m=o(l,[["render",r]]);export{c as __pageData,m as default};
